def test_hlsl_codegen_lowers_canonical_relative_shuffle_wave_ops():
    # WaveShuffleDown/Up/Xor (canonical for Metal simd_shuffle_down/up/xor) have
    # no native HLSL wave op, so they emulate via WaveReadLaneAt against a lane
    # offset relative to the current one. The emitted form matches the
    # function-call helper path (generate_hlsl_metal_simd_shuffle_call).
    code = """
    shader HLSLRelativeShuffle {
        compute {
            void main() {
                uint v = WaveGetLaneIndex();
                uint down = WaveShuffleDown(v, 1u);
                uint up = WaveShuffleUp(down, 1u);
                uint xored = WaveShuffleXor(up, 2u);
            }
        }
    }
    """
    tokens = tokenize_code(code)
    ast = parse_code(tokens)
    generated = generate_code(ast)

    assert "WaveReadLaneAt(v, (WaveGetLaneIndex() + uint(1u)))" in generated
    assert "WaveReadLaneAt(down, (WaveGetLaneIndex() - uint(1u)))" in generated
    assert "WaveReadLaneAt(up, (WaveGetLaneIndex() ^ uint(2u)))" in generated
    assert "WaveShuffle" not in generated


def test_hlsl_user_call_wave_arguments_are_not_probed_as_texture_calls(monkeypatch):
    code = """
    shader HLSLUserCallWaveArguments {
        struct complex64_t {
            float real;
            float imag;
        };

        complex64_t makeComplex(float real, float imag) {
            complex64_t value;
            value.real = real;
            value.imag = imag;
            return value;
        }

        complex64_t shuffled(float real, float imag, uint delta) {
            return makeComplex(
                WaveShuffleDown(real, delta),
                WaveShuffleDown(imag, delta));
        }

        compute {
            void main() {
                complex64_t value = shuffled(1.0, 2.0, 1u);
            }
        }
    }
    """
    codegen = HLSLCodeGen()
    original_validator = codegen.validate_query_lod_coordinate_argument

    def reject_user_function_texture_probe(func_name, args):
        if func_name == "makeComplex":
            pytest.fail("ordinary user function was probed as a texture operation")
        return original_validator(func_name, args)

    monkeypatch.setattr(
        codegen,
        "validate_query_lod_coordinate_argument",
        reject_user_function_texture_probe,
    )

    generated = codegen.generate(crosstl.translator.parse(code))

    assert "WaveReadLaneAt(real, (WaveGetLaneIndex() + uint(delta)))" in generated
    assert "WaveReadLaneAt(imag, (WaveGetLaneIndex() + uint(delta)))" in generated
    assert "requires float result context, got complex64_t" not in generated


def test_hlsl_codegen_lowers_canonical_shuffle_and_fill_up_wave_op(tmp_path):
    code = """
    shader HLSLShuffleAndFillUp {
        bool numericFlag(uint value, uint fill, uint delta) {
            return WaveShuffleAndFillUp(value, fill, delta);
        }

        compute {
            void main() {
                uint scalarResult = WaveShuffleAndFillUp(4u, 7u, 1u);
                uint segmentedResult = WaveShuffleAndFillUp(9u, 13u, 2u, 8u);
                uvec2 vectorResult = WaveShuffleAndFillUp(
                    uvec2(1u, 2u), uvec2(3u, 4u), 2u);
                bool boolResult = WaveShuffleAndFillUp(true, false, 1u);
                bool convertedResult = numericFlag(1u, 0u, 1u);
            }
        }
    }
    """

    generated = generate_code(parse_code(tokenize_code(code)))

    assert (
        "uint __crossgl_wave_shuffle_and_fill_up_uint("
        "uint value, uint fill, uint delta, uint modulo)" in generated
    )
    assert (
        "uint2 __crossgl_wave_shuffle_and_fill_up_uint2("
        "uint2 value, uint2 fill, uint delta, uint modulo)" in generated
    )
    assert (
        "bool __crossgl_wave_shuffle_and_fill_up_bool("
        "bool value, bool fill, uint delta, uint modulo)" in generated
    )
    assert "uint segmentLane = lane % modulo;" in generated
    assert "uint segmentBase = lane - segmentLane;" in generated
    assert "bool useValue = segmentLane >= delta;" in generated
    assert "uint valueSourceLane = useValue ? (lane - delta) : lane;" in generated
    assert (
        "uint fillSourceLane = useValue\n"
        "        ? lane\n"
        "        : (segmentBase + modulo + segmentLane - delta);" in generated
    )
    assert "WaveReadLaneAt(value, valueSourceLane)" in generated
    assert "WaveReadLaneAt(fill, fillSourceLane)" in generated
    assert "return useValue ? shuffled : shuffledFill;" in generated
    assert (
        "__crossgl_wave_shuffle_and_fill_up_uint("
        "4u, 7u, 1u, WaveGetLaneCount())" in generated
    )
    assert "__crossgl_wave_shuffle_and_fill_up_uint(9u, 13u, 2u, 8u)" in generated
    assert (
        "return ((__crossgl_wave_shuffle_and_fill_up_uint("
        "value, fill, delta, WaveGetLaneCount())) != 0);" in generated
    )
    assert "WaveShuffleAndFillUp" not in generated

    dxc = shutil.which("dxc")
    if dxc is not None:
        source = tmp_path / "wave-shuffle-and-fill-up.hlsl"
        output = tmp_path / "wave-shuffle-and-fill-up.dxil"
        source.write_text(generated, encoding="utf-8")
        result = subprocess.run(
            [
                dxc,
                "-T",
                "cs_6_0",
                "-E",
                "CSMain",
                str(source),
                "-Fo",
                str(output),
            ],
            check=False,
            capture_output=True,
            text=True,
        )
        assert result.returncode == 0, result.stdout + result.stderr


def test_hlsl_codegen_widens_native_uint16_shuffle_and_fill_up_delta():
    code = """
    shader HLSLShuffleAndFillUpNativeUint16Delta {
        StructuredBuffer<bfloat16_t> input;
        RWStructuredBuffer<bfloat16_t> output;

        uint shuffleWithDelta(uint value, uint fill, uint16_t delta) {
            return WaveShuffleAndFillUp(value, fill, delta);
        }

        compute {
            layout(local_size_x = 1, local_size_y = 1, local_size_z = 1) in;
            void main() {
                uint16_t delta = uint16_t(1u);
                uint shuffled = shuffleWithDelta(4u, 7u, delta);
                output[0] = input[shuffled];
            }
        }
    }
    """

    generated = HLSLCodeGen(target_profile="dx12").generate(
        parse_code(tokenize_code(code))
    )

    assert "StructuredBuffer<uint16_t> input : register(t0);" in generated
    assert "RWStructuredBuffer<uint16_t> output : register(u0);" in generated
    assert "uint shuffleWithDelta(uint value, uint fill, uint16_t delta)" in generated
    assert "uint16_t delta = uint16_t(1u);" in generated
    assert (
        "return __crossgl_wave_shuffle_and_fill_up_uint("
        "value, fill, uint(delta), WaveGetLaneCount());" in generated
    )
    assert "min16uint" not in generated


