def test_directx_interpolation_builtins_lower_to_hlsl_intrinsics():
    shader = """
    shader InterpolationBuiltins {
        struct FSInput {
            vec4 color;
        };

        vec4 shade(vec4 color, uint sampleIndex, ivec2 offset) {
            vec4 atSample = interpolateAtSample(color, sampleIndex);
            vec4 atOffset = interpolateAtOffset(color, offset);
            vec4 atCentroid = interpolateAtCentroid(color);
            return atSample + atOffset + atCentroid;
        }

        fragment {
            vec4 main(FSInput input) @ gl_FragColor {
                return shade(input.color, 0u, ivec2(1, -1));
            }
        }
    }
    """

    generated_code = generate_code(parse_code(tokenize_code(shader)))

    assert "EvaluateAttributeAtSample(color, sampleIndex)" in generated_code
    assert "EvaluateAttributeSnapped(color, offset)" in generated_code
    assert "EvaluateAttributeCentroid(color)" in generated_code
    assert "interpolateAtSample(" not in generated_code
    assert "interpolateAtOffset(" not in generated_code
    assert "interpolateAtCentroid(" not in generated_code


def test_directx_interpolation_modifiers_are_preserved_on_stage_interfaces():
    shader = """
    shader InterpolationModifierRoundTrip {
        vertex {
            struct VertexOutput {
                vec4 position @SV_Position;
                int materialId @TEXCOORD0 @nointerpolation;
                vec2 centerUv @TEXCOORD1 @centroid;
                vec4 sampleColor @TEXCOORD2 @sample;
                vec2 affineUv @TEXCOORD3 @noperspective;
            }

            VertexOutput main() {
                VertexOutput output;
                output.position = vec4(0.0, 0.0, 0.0, 1.0);
                output.materialId = 7;
                output.centerUv = vec2(0.25, 0.5);
                output.sampleColor = vec4(1.0);
                output.affineUv = vec2(0.75, 1.0);
                return output;
            }
        }

        fragment {
            vec4 main(
                int materialId @TEXCOORD0 @nointerpolation,
                vec2 centerUv @TEXCOORD1 @centroid,
                vec4 sampleColor @TEXCOORD2 @sample,
                vec2 affineUv @TEXCOORD3 @noperspective
            ) @SV_Target {
                return sampleColor
                    + vec4(centerUv + affineUv, float(materialId), 1.0);
            }
        }
    }
    """

    generated_code = generate_code(parse_code(tokenize_code(shader)))

    assert "nointerpolation int materialId: TEXCOORD0;" in generated_code
    assert "centroid float2 centerUv: TEXCOORD1;" in generated_code
    assert "sample float4 sampleColor: TEXCOORD2;" in generated_code
    assert "noperspective float2 affineUv: TEXCOORD3;" in generated_code
    assert "nointerpolation int materialId : TEXCOORD0" in generated_code
    assert "centroid float2 centerUv : TEXCOORD1" in generated_code
    assert "sample float4 sampleColor : TEXCOORD2" in generated_code
    assert "noperspective float2 affineUv : TEXCOORD3" in generated_code


def test_directx_precise_modifiers_emit_hlsl_declaration_syntax_from_docs():
    # Microsoft Learn HLSL variable syntax recommends marking precise shader
    # outputs directly on structure fields, output parameters, or entry returns.
    shader = """
    shader DirectXPreciseOutputs {
        fragment {
            struct FragmentOutput {
                vec4 color @ SV_Target @precise;
            }

            @precise
            vec4 preciseReturn(vec4 color @ TEXCOORD0) @ SV_Target {
                return color;
            }

            void writeOutput(
                out vec4 outputColor @ SV_Target @precise,
                vec4 value @ TEXCOORD0
            ) {
                outputColor = value;
            }

            vec4 main(vec4 color @ TEXCOORD0) @ SV_Target {
                vec4 localColor @precise = color * 2.0;
                return localColor;
            }
        }
    }
    """

    generated_code = generate_code(parse_code(tokenize_code(shader)))

    assert "precise float4 color: SV_Target;" in generated_code
    assert (
        "void writeOutput(out precise float4 outputColor : SV_Target" in generated_code
    )
    assert (
        "precise float4 preciseReturn(float4 color : TEXCOORD0): SV_Target"
        in generated_code
    )
    assert "precise float4 localColor = (color * 2.0);" in generated_code
    assert ": precise" not in generated_code


