def test_hlsl_stage_entry_buffer_pointer_params_promote_to_resources():
    shader = """
    shader MatMulPointerParameters {
        struct MatMulParams {
            uint row_dim_x;
            uint col_dim_x;
            uint inner_dim;
        }

        compute {
            @ stage_entry
            void mat_mul_simple1(
                ConstantBuffer<MatMulParams> params @buffer(0),
                float* A @buffer(1),
                float* B @buffer(2),
                float* X @buffer(3),
                uvec3 id_dispatchThreadID @gl_GlobalInvocationID
            ) {
                uint row = id_dispatchThreadID.y;
                uint col = id_dispatchThreadID.x;
                float sum = 0.0;
                for (uint k = 0; k < params.inner_dim; k++) {
                    sum += A[row * params.inner_dim + k] *
                        B[k * params.col_dim_x + col];
                }
                X[row * params.col_dim_x + col] = sum;
            }
        }
    }
    """

    generated_code = generate_code(parse_code(tokenize_code(shader)))

    assert "ConstantBuffer<MatMulParams> params : register(b0);" in generated_code
    assert "RWStructuredBuffer<float> A : register(u1);" in generated_code
    assert "RWStructuredBuffer<float> B : register(u2);" in generated_code
    assert "RWStructuredBuffer<float> X : register(u3);" in generated_code
    assert (
        "void CSMain(uint3 id_dispatchThreadID : SV_DispatchThreadID)" in generated_code
    )
    assert "float* A" not in generated_code
    assert "float* B" not in generated_code
    assert "float* X" not in generated_code
    assert "void CSMain(float*" not in generated_code
    HLSLParser(HLSLLexer(generated_code).tokenize()).parse()


def test_hlsl_stage_entry_storage_arrays_promote_to_resources():
    shader = """
    // HIP to CrossGL conversion
    // Kernel: AddKernel
    @compute
    @stage_entry
    @workgroup_size(1, 1, 1)
    fn AddKernel(
        @group(0) @binding(0) var<storage, read_write> a: array<f32>,
        @group(0) @binding(1) var<storage, read> b: array<f32>
    ) {
        var global_idx: i32 = (
            gl_LocalInvocationID.x + (gl_WorkGroupID.x * gl_WorkGroupSize.x)
        );
        a[global_idx] += b[global_idx];
    }
    """

    generated_code = generate_code(parse_code(tokenize_code(shader)))

    assert "RWStructuredBuffer<float> a : register(u0);" in generated_code
    assert "StructuredBuffer<float> b : register(t1);" in generated_code
    assert (
        "void CSMain(uint3 groupThreadID : SV_GroupThreadID, "
        "uint3 groupID : SV_GroupID)"
    ) in generated_code
    assert "a[global_idx] += b[global_idx];" in generated_code
    assert ": group" not in generated_code
    assert "float a[]" not in generated_code
    assert "float b[]" not in generated_code
    assert re.search(r"void CSMain\([^)]*StructuredBuffer", generated_code) is None
    assert re.search(r"void CSMain\([^)]*float\s+[ab]\[\]", generated_code) is None
    assert "gl_LocalInvocationID" not in generated_code
    assert "gl_WorkGroupID" not in generated_code
    assert "gl_WorkGroupSize" not in generated_code
    HLSLParser(HLSLLexer(generated_code).tokenize()).parse()


