def test_directx_layout_descriptor_array_binding_overlap_relocates_registers():
    code = """
    shader VulkanDynamicDescriptorArrayIndexShader {
        struct Particle {
            vec3 position;
            float mass;
        }

        compute {
            layout(local_size_x = 1, local_size_y = 1, local_size_z = 1) in;
            layout(set = 0, binding = 0) buffer Particle* particles[2];
            layout(set = 0, binding = 1) buffer int* descriptors;
            layout(set = 0, binding = 2) uniform sampler2D colorMaps[2];
            layout(set = 0, binding = 5) sampler linearSamplers[2];

            void main() {
                int descriptor = descriptors[0];
                vec2 uv = particles[descriptor][0].position.xy;
                vec4 color = textureLod(
                    colorMaps[descriptor],
                    linearSamplers[descriptor],
                    uv,
                    0.25
                );
                float mass = particles[descriptor][0].mass;
                particles[descriptor][1].mass = mass + color.x;
                return;
            }
        }
    }
    """

    generated_code = generate_code(parse_code(tokenize_code(code)))

    assert "RWStructuredBuffer<Particle> particles[2] : register(u0);" in generated_code
    assert "RWStructuredBuffer<int> descriptors : register(u2);" in generated_code
    assert "Texture2D colorMaps[2] : register(t2);" in generated_code
    assert "SamplerState linearSamplers[2] : register(s5);" in generated_code
    assert "int descriptor = descriptors[0];" in generated_code
    assert "float2 uv = particles[descriptor][0].position.xy;" in generated_code
    assert "particles[descriptor][1].mass = (mass + color.x);" in generated_code


def test_directx_layout_nonuniform_descriptor_array_overlap_relocates_registers():
    code = """
    shader VulkanNonUniformDescriptorArrayIndexShader {
        struct Particle {
            vec3 position;
            float mass;
        }

        compute {
            layout(local_size_x = 1, local_size_y = 1, local_size_z = 1) in;
            layout(set = 0, binding = 0) buffer Particle* particles[2];
            layout(set = 0, binding = 1) buffer int* descriptors;
            layout(set = 0, binding = 2) uniform sampler2D colorMaps[2];
            layout(set = 0, binding = 5) sampler linearSamplers[2];

            void main() {
                int descriptor = descriptors[0];
                vec2 uv = particles[nonuniform(descriptor)][0].position.xy;
                vec4 color = textureLod(
                    colorMaps[nonuniform(descriptor)],
                    linearSamplers[nonuniform(descriptor)],
                    uv,
                    0.25
                );
                float mass = particles[nonuniform(descriptor)][0].mass;
                particles[nonuniform(descriptor)][1].mass = mass + color.x;
                return;
            }
        }
    }
    """

    generated_code = generate_code(parse_code(tokenize_code(code)))

    assert "RWStructuredBuffer<Particle> particles[2] : register(u0);" in generated_code
    assert "RWStructuredBuffer<int> descriptors : register(u2);" in generated_code
    assert "Texture2D colorMaps[2] : register(t2);" in generated_code
    assert "SamplerState linearSamplers[2] : register(s5);" in generated_code
    assert "NonUniformResourceIndex(descriptor)" in generated_code
    assert "nonuniform(descriptor)" not in generated_code


def test_directx_relocatable_resource_allocator_bounds_range_inspections():
    resource_count = 512
    integer_type = PrimitiveType("int")
    resources = []
    for index in range(resource_count):
        space = 7 + index % 2
        resources.append(
            VariableNode(
                f"resource_{index}",
                ArrayType(
                    NamedType("RWStructuredBuffer<int>"),
                    LiteralNode(2, integer_type),
                ),
                attributes=[
                    AttributeNode("buffer", [LiteralNode(0, integer_type)]),
                    AttributeNode("space", [LiteralNode(space, integer_type)]),
                ],
                annotations={
                    "directx.relocatable_binding": True,
                    "directx.binding_provenance": (
                        f"stage-entry parameter entry_{index}.resource"
                    ),
                },
            )
        )

    codegen = HLSLCodeGen()
    allocator = codegen.new_directx_resource_register_allocator()
    codegen.reserve_explicit_global_resource_registers(resources, allocator)

    expected_ranges = [(start, start + 1) for start in range(0, 512, 2)]
    assert [record[:2] for record in allocator[("u", "space7")]] == expected_ranges
    assert [record[:2] for record in allocator[("u", "space8")]] == expected_ranges
    assert allocator.relocation_cursors == {
        ("u", "space7"): 512,
        ("u", "space8"): 512,
    }
    assert allocator[("u", "space7")][-1][2:] == (
        "resource_510",
        "stage-entry parameter entry_510.resource",
    )
    assert allocator[("u", "space8")][-1][2:] == (
        "resource_511",
        "stage-entry parameter entry_511.resource",
    )
    assert allocator.range_inspection_count <= resource_count * 10


def test_directx_sorted_resource_allocator_preserves_conflict_provenance_order():
    codegen = HLSLCodeGen()
    allocator = codegen.new_directx_resource_register_allocator()
    codegen.reserve_resource_register_range(
        allocator,
        "t",
        10,
        2,
        "reservedFirst",
        "space3",
        provenance="first declaration",
    )
    codegen.reserve_resource_register_range(
        allocator,
        "t",
        0,
        2,
        "reservedSecond",
        "space3",
        provenance="second declaration",
    )

    with pytest.raises(ValueError) as exc_info:
        codegen.reserve_resource_register_range(
            allocator,
            "t",
            1,
            10,
            "overlapping",
            "space3",
            provenance="conflicting declaration",
        )

    assert str(exc_info.value) == (
        "Conflicting DirectX resource binding for 'overlapping': "
        "t1-t10, space3 overlaps 'reservedFirst' t10-t11, space3 "
        "(overlapping: conflicting declaration; reservedFirst: first declaration)"
    )


def test_hlsl_auto_registers_skip_later_explicit_global_bindings():
    code = """
    shader LateExplicitBindings {
        sampler2D autoTexture;
        image2D autoImage;
        sampler autoSampler;

        cbuffer AutoBlock {
            vec4 autoTint;
        };

        sampler2D explicitTexture @register(t0);
        RWStructuredBuffer<int> explicitValues @register(u0);
        sampler explicitSampler @register(s0);

        cbuffer ExplicitBlock @register(b0) {
            vec4 explicitTint;
        };

        fragment {
            vec4 main(vec2 uv @TEXCOORD0) @gl_FragColor {
                vec4 stored = imageLoad(autoImage, ivec2(0, 0));
                int value = buffer_load(explicitValues, 0);
                return texture(autoTexture, autoSampler, uv) +
                    texture(explicitTexture, explicitSampler, uv) +
                    stored + autoTint + explicitTint + vec4(float(value));
            }
        }
    }
    """

    generated_code = HLSLCodeGen().generate_stage(
        crosstl.translator.parse(code), "fragment"
    )

    assert "Texture2D autoTexture : register(t1);" in generated_code
    assert "RWTexture2D<float4> autoImage : register(u1);" in generated_code
    assert "SamplerState autoSampler : register(s1);" in generated_code
    assert "cbuffer AutoBlock : register(b1)" in generated_code
    assert "Texture2D explicitTexture : register(t0);" in generated_code
    assert "RWStructuredBuffer<int> explicitValues : register(u0);" in generated_code
    assert "SamplerState explicitSampler : register(s0);" in generated_code
    assert "cbuffer ExplicitBlock : register(b0)" in generated_code


