def test_directx_buffer_struct_qualifier_lowers_to_rwstructuredbuffer():
    shader = """
    shader HlslStructBuffer {
        struct Particle {
            vec3 position;
            int active;
        }

        struct ParticleBlock {
            Particle particles[4];
            int active_count;
        }

        compute {
            buffer ParticleBlock particle_buffer;

            void main() {
                Particle particle = particle_buffer.particles[1];
                particle.position = vec3(1.0);
                particle_buffer.particles[1] = particle;
                atomicAdd(particle_buffer.active_count, 1);
            }
        }
    }
    """

    generated_code = HLSLCodeGen().generate(crosstl.translator.parse(shader))

    assert (
        "RWStructuredBuffer<ParticleBlock> particle_buffer : register(u0);"
        in generated_code
    )
    assert "Particle particle = particle_buffer[0].particles[1];" in generated_code
    assert "particle_buffer[0].particles[1] = particle;" in generated_code
    assert "InterlockedAdd(particle_buffer[0].active_count, 1);" in generated_code
    assert "static ParticleBlock particle_buffer;" not in generated_code


def test_struct_constructor_and_inferred_generic_constructor_local():
    shader = """
    shader StructConstructors {
        struct Geometry {
            center: vec3;
            normal: vec3;
        }

        generic<T> struct Box {
            value: T;
        }

        Geometry make_geometry(vec3 center, vec3 normal) {
            return Geometry { center: center, normal: normal };
        }

        Box<float> make_box(vec3 value) {
            let normalized = normalize(value);
            let wrapped = Box { value: normalized.x };
            return wrapped;
        }
    }
    """

    generated_code = HLSLCodeGen().generate(crosstl.translator.parse(shader))

    assert "struct Geometry {" in generated_code
    assert "struct Box_float {" in generated_code
    assert "Geometry make_geometry(float3 center, float3 normal)" in generated_code
    assert "Geometry __crossgl_struct_return_0;" in generated_code
    assert "__crossgl_struct_return_0.center = center;" in generated_code
    assert "__crossgl_struct_return_0.normal = normal;" in generated_code
    assert "return __crossgl_struct_return_0;" in generated_code
    assert "Box_float make_box(float3 value)" in generated_code
    assert "float3 normalized = normalize(value);" in generated_code
    assert "Box_float wrapped;" in generated_code
    assert "wrapped.value = normalized.x;" in generated_code
    assert "return wrapped;" in generated_code
    assert "Option_Self normalized" not in generated_code
    assert "Box<" not in generated_code
    assert "ConstructorNode(" not in generated_code


