def test_directx_function_local_groupshared_variables_lower_to_global_scope():
    shader = """
    shader LocalGroupShared {
        task {
            void main() @numthreads(1, 1, 1) {
                groupshared uint scratch;
                scratch = 1u;
                DispatchMesh(1, 1, 1);
            }
        }
    }
    """

    generated = HLSLCodeGen().generate_stage(crosstl.translator.parse(shader), "task")

    assert "groupshared uint main_scratch;" in generated
    assert "    groupshared uint scratch;" not in generated
    assert "main_scratch = 1u;" in generated
    assert generated.index("groupshared uint main_scratch;") < generated.index(
        '[shader("amplification")]'
    )


def test_directx_function_local_threadgroup_duplicate_names_are_disambiguated():
    shader = """
    shader DuplicateLocalGroupShared {
        compute {
            void main() {
                if (true) {
                    threadgroup uint scratch[4];
                    scratch[0] = 1u;
                }
                threadgroup uint scratch[4];
                scratch[1] = 2u;
            }
        }
    }
    """

    generated = HLSLCodeGen().generate_stage(
        crosstl.translator.parse(shader), "compute"
    )

    assert "groupshared uint main_scratch[4];" in generated
    assert "groupshared uint main_scratch_[4];" in generated
    assert "groupshared uint scratch" not in generated
    assert "main_scratch[0] = 1u;" in generated
    assert "main_scratch_[1] = 2u;" in generated
    assert generated.index("groupshared uint main_scratch[4];") < generated.index(
        "void CSMain()"
    )


def test_directx_groupshared_extents_resolve_lexical_const_int_aliases():
    shader = """
    shader LexicalGroupSharedExtents {
        compute {
            void main() {
                const int BASE = 4;
                const int WIDTH = BASE * 2;
                threadgroup uint outer[WIDTH];
                threadgroup uint arithmetic[3 * WIDTH];
                if (true) {
                    const int BASE = 8;
                    const int WIDTH = BASE * 2;
                    threadgroup uint inner[WIDTH];
                }
                threadgroup uint after[WIDTH];
            }
        }
    }
    """

    generated = HLSLCodeGen().generate_stage(
        crosstl.translator.parse(shader), "compute"
    )

    assert "groupshared uint main_outer[8];" in generated
    assert "groupshared uint main_arithmetic[(3 * 8)];" in generated
    assert "groupshared uint main_inner[16];" in generated
    assert "groupshared uint main_after[8];" in generated
    global_declarations = generated.split("void CSMain()", maxsplit=1)[0]
    assert "BASE" not in global_declarations
    assert "WIDTH" not in global_declarations


