        pytest.param("float", "uint", "asuint(input[uint(0)])", id="floating-source"),
        pytest.param("uint", "int", "asint(input[uint(0)])", id="signed-target"),
        pytest.param("uint", "float", "asfloat(input[uint(0)])", id="floating-target"),
